INSERT INTO product_definitions (product_slug, name, description, price, total_steps, estimated_duration, model, is_active, display_order, product_group, system_prompt, final_deliverable_prompt, steps) VALUES ('personal-alignment', 'Personal Alignment Orientation', 'Discover your core values, life purpose, and authentic self using Astrology & Human Design.', 7.00, 5, '15-20 minutes', 'gpt-4o', true, 6, 'orientation', 'You are the Personal Alignment Guide AI. Help people discover WHO they are at their core.', 'Create a Personal Alignment Blueprint with: Core Identity, Value System, Energy Architecture, Identity Evolution, Life Vision, Life Purpose, Alignment Action Plan.', '[{"step":1,"title":"Upload Your Charts","subtitle":"Upload your charts","question":"Please upload your birth chart files.","prompt":"Thank you for uploading!","allow_file_upload":true,"required":true,"max_follow_ups":0},{"step":2,"title":"Life Satisfaction & Core Values","subtitle":"Discover what matters","question":"Rate your life alignment 1-10 and share what matters most.","prompt":"Extract core values.","allow_file_upload":false,"required":true,"max_follow_ups":3},{"step":3,"title":"Energy Architecture","subtitle":"What fuels you","question":"What energizes vs drains you?","prompt":"Identify HD type.","allow_file_upload":false,"required":true,"max_follow_ups":3},{"step":4,"title":"Identity Evolution","subtitle":"Your growth","question":"Who were you 5 years ago vs now?","prompt":"Reference Saturn, Pluto, North Node.","allow_file_upload":false,"required":true,"max_follow_ups":3},{"step":5,"title":"Life Purpose","subtitle":"Your calling","question":"What is your Life Task?","prompt":"Synthesize into clarity.","allow_file_upload":false,"required":true,"max_follow_ups":3}]'::jsonb);
INSERT INTO product_definitions (product_slug, name, description, price, total_steps, estimated_duration, model, is_active, display_order, product_group, system_prompt, final_deliverable_prompt, steps) VALUES ('business-alignment', 'Business Alignment Orientation', 'Build your personalized brand blueprint based on your Astrology and Human Design.', 7.00, 5, '15-20 minutes', 'gpt-4o', true, 7, 'orientation', 'You are a Quantum Business Framework expert helping users build their personalized brand blueprint.', 'Generate a Quantum Blueprint with: Astrological Overview, Human Design Integration, Brand Archetype, Offer Clarity, Strategic Focus.', '[{"step":1,"title":"Upload Your Charts","subtitle":"Upload your charts","question":"Please upload your birth chart files.","prompt":"Thank you for uploading!","allow_file_upload":true,"required":true,"max_follow_ups":0},{"step":2,"title":"Business Overview","subtitle":"Your business","question":"Describe your business or idea.","prompt":"Help articulate clearly.","allow_file_upload":true,"required":true,"max_follow_ups":3},{"step":3,"title":"Current Challenge","subtitle":"Your blocks","question":"Biggest challenge right now?","prompt":"Find the real bottleneck.","allow_file_upload":false,"required":true,"max_follow_ups":3},{"step":4,"title":"Human Design","subtitle":"Your blueprint","question":"Know your HD type?","prompt":"Explain HD basics.","allow_file_upload":false,"required":false,"max_follow_ups":3},{"step":5,"title":"Vision & Goals","subtitle":"Your future","question":"What does success look like?","prompt":"Articulate goals.","allow_file_upload":false,"required":true,"max_follow_ups":3}]'::jsonb);
